  "inlineSchema": "// prisma/schema.prisma\n// ─────────────────────────────────────────────────────────────────\n// Database schema for the Attendance Management System\n// Uses PostgreSQL via Prisma ORM\n// ─────────────────────────────────────────────────────────────────\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ── User (Organization owner / tenant) ──────────────────────────\nmodel User {\n  id           String   @id @default(cuid())\n  name         String\n  email        String   @unique\n  password     String // bcrypt hashed\n  organization String // Organization/company name\n  role         UserRole @default(ADMIN)\n  isActive     Boolean  @default(true)\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n\n  // Relations — all data is scoped to this user (multi-tenant)\n  employees Employee[]\n  holidays  Holiday[]\n  settings  OrgSettings?\n\n  @@map(\"users\")\n}\n\nenum UserRole {\n  SUPER_ADMIN\n  ADMIN\n  MANAGER\n}\n\n// ── Organization Settings ────────────────────────────────────────\nmodel OrgSettings {\n  id          String   @id @default(cuid())\n  userId      String   @unique\n  workingDays Int      @default(26) // Days used for salary calc\n  weeklyOff   Json     @default(\"[0,6]\") // 0=Sun, 6=Sat (JSON array)\n  currency    String   @default(\"USD\")\n  timezone    String   @default(\"UTC\")\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@map(\"org_settings\")\n}\n\n// ── Employee ─────────────────────────────────────────────────────\nmodel Employee {\n  id          String   @id @default(cuid())\n  userId      String // Foreign key → User (tenant isolation)\n  name        String\n  age         Int\n  salary      Decimal  @db.Decimal(12, 2) // Monthly salary\n  role        String // Job title / position\n  department  String?\n  joiningDate DateTime\n  email       String?\n  phone       String?\n  address     String?\n  isActive    Boolean  @default(true)\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  // Relations\n  user          User           @relation(fields: [userId], references: [id], onDelete: Cascade)\n  attendance    Attendance[]\n  leaveRequests LeaveRequest[]\n\n  // Composite index for fast tenant-scoped queries\n  @@index([userId, isActive])\n  @@index([userId, name])\n  @@map(\"employees\")\n}\n\n// ── Attendance Record ─────────────────────────────────────────────\nmodel Attendance {\n  id         String           @id @default(cuid())\n  employeeId String\n  userId     String // Denormalized for fast tenant queries\n  date       DateTime         @db.Date\n  status     AttendanceStatus\n  note       String? // Optional note (e.g., reason for leave)\n  checkIn    DateTime? // Optional check-in time\n  checkOut   DateTime? // Optional check-out time\n  createdAt  DateTime         @default(now())\n  updatedAt  DateTime         @updatedAt\n\n  employee Employee @relation(fields: [employeeId], references: [id], onDelete: Cascade)\n\n  // Prevent duplicate attendance for same employee on same day\n  @@unique([employeeId, date])\n  @@index([userId, date])\n  @@index([employeeId, date])\n  @@map(\"attendance\")\n}\n\nenum AttendanceStatus {\n  PRESENT\n  ABSENT\n  LEAVE\n  HALF_DAY\n  HOLIDAY\n}\n\n// ── Leave Request ────────────────────────────────────────────────\nmodel LeaveRequest {\n  id         String      @id @default(cuid())\n  employeeId String\n  userId     String\n  startDate  DateTime    @db.Date\n  endDate    DateTime    @db.Date\n  type       LeaveType\n  reason     String\n  status     LeaveStatus @default(PENDING)\n  reviewedAt DateTime?\n  createdAt  DateTime    @default(now())\n  updatedAt  DateTime    @updatedAt\n\n  employee Employee @relation(fields: [employeeId], references: [id], onDelete: Cascade)\n\n  @@index([employeeId, status])\n  @@index([userId, status])\n  @@map(\"leave_requests\")\n}\n\nenum LeaveType {\n  SICK\n  CASUAL\n  ANNUAL\n  UNPAID\n  OTHER\n}\n\nenum LeaveStatus {\n  PENDING\n  APPROVED\n  REJECTED\n}\n\n// ── Holiday Calendar ─────────────────────────────────────────────\nmodel Holiday {\n  id          String   @id @default(cuid())\n  userId      String\n  name        String\n  date        DateTime @db.Date\n  description String?\n  createdAt   DateTime @default(now())\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, date])\n  @@index([userId, date])\n  @@map(\"holidays\")\n}\n",
